mapper.insert:
/* 정산: 행 추가 (대기 상태) */
INSERT INTO SETTLEMENT (TRD_SN, USR_SN, STLM_AMT, STLM_STATUS_CD)
VALUES (#{trdSn}, #{usrSn}, #{stlmAmt}, #{stlmStatusCd})

mapper.select:
/* 정산: 행 잠금 조회 (상태 전이 검증용) */
SELECT STLM_SN, TRD_SN, USR_SN, STLM_AMT, STLM_STATUS_CD, STLM_REG_DT, STLM_UPDT_DT
FROM SETTLEMENT
WHERE STLM_SN = #{stlmSn}
FOR UPDATE

mapper.update:
/* 정산: 상태코드 갱신 */
UPDATE SETTLEMENT
SET STLM_STATUS_CD = #{statusCd}
WHERE STLM_SN = #{stlmSn}

mapper.select:
/* 정산: 회원별 목록 (최신순 100건) */
SELECT STLM_SN, TRD_SN, USR_SN, STLM_AMT, STLM_STATUS_CD, STLM_REG_DT, STLM_UPDT_DT
FROM SETTLEMENT
WHERE USR_SN = #{usrSn}
ORDER BY STLM_SN DESC
LIMIT 100

/* 정산: 거래별 목록 */
SELECT STLM_SN, TRD_SN, USR_SN, STLM_AMT, STLM_STATUS_CD, STLM_REG_DT, STLM_UPDT_DT
FROM SETTLEMENT
WHERE TRD_SN = #{trdSn}
ORDER BY STLM_SN DESC
